sequence.script:
var res = mc.getPayloadJSON();
var doc = null;

if (res && res.found === true && res.data && Array.isArray(res.data) && res.data.length > 0) {
    doc = res.data[0];
} else if (Array.isArray(res) && res.length > 0) {
    doc = res[0];
}

if (doc) {
    if (doc._id) {
        delete doc._id;
    }

    if (doc.adjusterDetails) {
        if (doc.adjusterDetails.assignedDate &&
            typeof doc.adjusterDetails.assignedDate === 'object' &&
            doc.adjusterDetails.assignedDate.$date) {
            doc.adjusterDetails.assignedDate = doc.adjusterDetails.assignedDate.$date;
        }

        if (doc.adjusterDetails.inspectionDate &&
            typeof doc.adjusterDetails.inspectionDate === 'object' &&
            doc.adjusterDetails.inspectionDate.$date) {
            doc.adjusterDetails.inspectionDate = doc.adjusterDetails.inspectionDate.$date;
        }
    }

    var response = {
        claimId: doc.claimId,
        inspectionId: doc.inspectionId,
        inspectionType: doc.inspectionType,
        inspectionStatus: doc.inspectionStatus,
        adjusterDetails: {
            adjusterId: doc.adjusterDetails ? doc.adjusterDetails.adjusterId : null,
            adjusterType: doc.adjusterDetails ? doc.adjusterDetails.adjusterType : null,
            assignedDate: doc.adjusterDetails ? doc.adjusterDetails.assignedDate : null,
            inspectionDate: doc.adjusterDetails ? doc.adjusterDetails.inspectionDate : null
        },
        lossItemReference: {
            lossItemIdentifier: doc.lossItemReference ? doc.lossItemReference.lossItemIdentifier : null,
            insurableObjectIdentifier: doc.lossItemReference ? doc.lossItemReference.insurableObjectIdentifier : null,
            coverageIdentifier: doc.lossItemReference ? doc.lossItemReference.coverageIdentifier : null,
            lossTypeCode: doc.lossItemReference ? doc.lossItemReference.lossTypeCode : null,
            damageCategory: doc.lossItemReference ? doc.lossItemReference.damageCategory : null
        },
        inspectionFindings: {
            damageConfirmed: doc.inspectionFindings ? doc.inspectionFindings.damageConfirmed : null,
            damageDescription: doc.inspectionFindings ? doc.inspectionFindings.damageDescription : null,
            damageExtent: doc.inspectionFindings ? doc.inspectionFindings.damageExtent : null,
            severityCode: doc.inspectionFindings ? doc.inspectionFindings.severityCode : null,
            causeOfLossConfirmed: doc.inspectionFindings ? doc.inspectionFindings.causeOfLossConfirmed : null
        },
        assessment: {
            assessedLossAmount: doc.assessment ? doc.assessment.assessedLossAmount : null,
            currencyCode: doc.assessment ? doc.assessment.currencyCode : null,
            depreciationAmount: doc.assessment ? doc.assessment.depreciationAmount : null,
            deductibleAmount: doc.assessment ? doc.assessment.deductibleAmount : null,
            netPayableAmount: doc.assessment ? doc.assessment.netPayableAmount : null
        },
        inspectionOutcome: {
            recommendation: doc.inspectionOutcome ? doc.inspectionOutcome.recommendation : null,
            remarks: doc.inspectionOutcome ? doc.inspectionOutcome.remarks : null
        }
    };

    mc.setProperty("dataFound", "true");
    mc.setPayloadJSON(response);
} else {
    mc.setProperty("dataFound", "false");
}
